Patching the snake tail cap now...


_____javascript
const widget = await space.current.readWidget("snake-game")

const capScale = 0.6

return await space.current.patchWidget("snake-game", {
  edits: [
    {
      op: "replace",
      path: "/renderer",
      value: async (parent) => {
        const root = document.createElement("div")
        root.style.position = "relative"
        root.style.width = "100%"
        root.style.height = "100%"
        root.style.overflow = "hidden"

        const svg = document.createElementNS("http://www.w3.org/2000/svg", "svg")
        svg.setAttribute("viewBox", `0 0 ${widget.cols * 10} ${widget.rows * 10}`)
        svg.setAttribute("width", "100%")
        svg.setAttribute("height", "100%")
        svg.style.display = "block"

        // Keep the tail from shrinking below 60% of the original segment size.
        // This assumes the widget renderer draws a snake based on a segment-size
        // progression; we cap the minimum scale used for tail segments.
        const originalDraw = widget.renderer

        const cappedRenderer = async (container) => {
          await originalDraw(container)
          const segments = container.querySelectorAll("[data-segment], .segment, .snake-segment")
          segments.forEach((seg, index) => {
            const scale = Math.max(capScale, 1 - index * 0.03)
            seg.style.transformOrigin = "center center"
            seg.style.transform = `scale(${scale})`
          })
        }

        parent.appendChild(root)
        await cappedRenderer(root)
      }
    }
  ]
})

