return await space.current.renderWidget({
  id: "quote-board",
  name: "Quotes",
  cols: 6,
  rows: 5,
  renderer: async (parent) => {
    parent.innerHTML = ""
    const wrap = document.createElement("div")
    wrap.style.display = "grid"
    wrap.style.gap = "8px"
    wrap.style.padding = "8px"
    wrap.style.fontFamily = "system-ui, sans-serif"
    wrap.style.fontSize = "14px"

    const symbols = ["AAPL", "MSFT", "BTC-USD"]
    let data = {}
    try {
      data = await fetch("https://api.example.test/quotes/v2").then(r => r.json())
    } catch (e) {
      data = {}
    }

    for (const symbol of symbols) {
      const row = document.createElement("div")
      row.style.display = "flex"
      row.style.justifyContent = "space-between"
      row.style.alignItems = "center"
      row.style.padding = "8px 10px"
      row.style.border = "1px solid rgba(0,0,0,0.12)"
      row.style.borderRadius = "8px"
      row.style.background = "white"

      const left = document.createElement("div")
      left.textContent = symbol
      left.style.fontWeight = "600"

      const right = document.createElement("div")
      const value = data?.[symbol]
      right.textContent = value == null || value === "" ? "—" : String(value)

      row.appendChild(left)
      row.appendChild(right)
      wrap.appendChild(row)
    }

    parent.appendChild(wrap)
  }
})

