    parent.innerHTML = `
      <div style="padding:12px;font-family:sans-serif">
        <div style="font-weight:600;margin-bottom:8px">Quotes</div>
        <div id="quotes-status" style="margin-bottom:8px;color:#666">Loading…</div>
