      </div>
    `
    const status = parent.querySelector("#quotes-status")
    const list = parent.querySelector("#quotes-list")

    try {
      const symbols = ["AAPL", "MSFT", "BTC-USD"]
      const url = "https://api.example.test/quotes"
      const data = await fetch(url).then(r => r.json())

      const rows = symbols.map((symbol) => {
        const item = data?.[symbol] ?? data?.quotes?.[symbol] ?? data?.find?.((q) => q.symbol === symbol)
        return item ? `${symbol}: ${item.price ?? item.value ?? item.last ?? "—"}` : `${symbol}: —`
      })

      status.textContent = "Live data loaded"
      list.innerHTML = rows.map((row) => `<div style="padding:8px;border:1px solid #ddd;border-radius:6px">${row}</div>`).join("")
    } catch (error) {
      status.textContent = "Feed unavailable"
      list.innerHTML = `
        <div style="padding:8px;border:1px solid #ddd;border-radius:6px">AAPL: —</div>
        <div style="padding:8px;border:1px solid #ddd;border-radius:6px">MSFT: —</div>
        <div style="padding:8px;border:1px solid #ddd;border-radius:6px">BTC-USD: —</div>
      `
    }
  }
})

