_____javascript
return await space.current.patchWidget("snake-game", {
  edits: [
    {
      op: "replace",
      path: "renderer",
      value: async (parent) => {
        parent.innerHTML = `
          <style>
            .board {
              position: relative;
              width: 100%;
              height: 100%;
              background: #111;
              overflow: hidden;
            }
            .cell {
              position: absolute;
              box-sizing: border-box;
              border: 1px solid rgba(255,255,255,0.05);
              transition:
                transform 120ms linear,
                left 120ms linear,
                top 120ms linear,
                width 120ms linear,
                height 120ms linear,
                opacity 120ms linear;
              will-change: transform, left, top;
            }
            .snake {
              background: #4ade80;
              border-radius: 6px;
              box-shadow: 0 0 8px rgba(74, 222, 128, 0.35);
            }
            .snake.head {
              background: #86efac;
              box-shadow: 0 0 12px rgba(134, 239, 172, 0.55);
            }
            .food {
              background: #ef4444;
              border-radius: 999px;
              box-shadow: 0 0 10px rgba(239, 68, 68, 0.5);
            }
          </style>
          <div class="board"></div>
        `

        const board = parent.querySelector(".board")
        const cols = 20
        const rows = 20
        let cellSize = 0

        const snake = [
          { x: 10, y: 10 },
          { x: 9, y: 10 },
          { x: 8, y: 10 }
        ]
        let food = { x: 14, y: 10 }
        let dir = { x: 1, y: 0 }
        let queuedDir = dir
        let moving = false

        const cells = new Map()

        function resize() {
          const w = board.clientWidth
          const h = board.clientHeight
          cellSize = Math.floor(Math.min(w / cols, h / rows))
          board.innerHTML = ""
          cells.clear()

          for (let y = 0; y < rows; y++) {
            for (let x = 0; x < cols; x++) {
              const c = document.createElement("div")
              c.className = "cell"
              c.style.left = `${x * cellSize}px`
              c.style.top = `${y * cellSize}px`
              c.style.width = `${cellSize}px`
              c.style.height = `${cellSize}px`
              board.appendChild(c)
            }
          }

          render()
        }

        function drawSnake() {
          // remove previous snake/food overlays
          for (const el of cells.values()) el.remove()
          cells.clear()

          snake.forEach((p, i) => {
            const el = document.createElement("div")
            el.className = `cell snake ${i === 0 ? "head" : ""}`
            el.style.left = `${p.x * cellSize}px`
            el.style.top = `${p.y * cellSize}px`
            el.style.width = `${cellSize}px`
            el.style.height = `${cellSize}px`
            el.style.transitionDuration = "120ms"
            board.appendChild(el)
            cells.set(`s${i}`, el)
          })

          const f = document.createElement("div")
          f.className = "cell food"
          f.style.left = `${food.x * cellSize}px`
          f.style.top = `${food.y * cellSize}px`
          f.style.width = `${cellSize}px`
          f.style.height = `${cellSize}px`
          f.style.transitionDuration = "120ms"
          board.appendChild(f)
          cells.set("food", f)
        }

        function render() {
          drawSnake()
        }

        function step() {
          if (moving) return
          moving = true
          dir = queuedDir

          const head = { ...snake[0] }
          const next = { x: head.x + dir.x, y: head.y + dir.y }

          if (next.x < 0 || next.x >= cols || next.y < 0 || next.y >= rows) {
            moving = false
            return
          }

          snake.unshift(next)

          const ate = next.x === food.x && next.y === food.y
          if (!ate) snake.pop()
          else food = { x: Math.floor(Math.random() * cols), y: Math.floor(Math.random() * rows) }

          render()

          requestAnimationFrame(() => {
            const els = Array.from(board.querySelectorAll(".cell.snake"))
            els.forEach((el, i) => {
              el.style.left = `${snake[i].x * cellSize}px`
              el.style.top = `${snake[i].y * cellSize}px`
            })
            const foodEl = board.querySelector(".cell.food")
            if (foodEl) {
              foodEl.style.left = `${food.x * cellSize}px`
              foodEl.style.top = `${food.y * cellSize}px`
            }

            setTimeout(() => {
              moving = false
            }, 130)
          })
        }

        window.addEventListener("keydown", (e) => {
          const map = {
            ArrowUp: { x: 0, y: -1 },
            ArrowDown: { x: 0, y: 1 },
            ArrowLeft: { x: -1, y: 0 },
            ArrowRight: { x: 1, y: 0 }
          }
          const nd = map[e.key]
          if (!nd) return
          if (nd.x === -dir.x && nd.y === -dir.y) return
          queuedDir = nd
        })

        new ResizeObserver(resize).observe(board)
        setInterval(step, 140)
        resize()
      }
    }
  ]
})

